// ── MAIN HANDLER ──────────────────────────────────────────────────────────────
export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const { document_type, profile_id, candidate_id, label, drive_folder_id } = body

    // Load settings
    const { data: settingsData } = await supabase.from('stock_settings').select('key,value')
    const sv: Record<string,string> = {}
    settingsData?.forEach((r: any) => { sv[r.key] = r.value })
    const settings = {
      ...LH_DEFAULTS,
      top:    parseInt(sv.lh_top_margin_mm    || '38'),
      bottom: parseInt(sv.lh_bottom_margin_mm || '20'),
      left:   parseInt(sv.lh_left_margin_mm   || '20'),
      right:  parseInt(sv.lh_right_margin_mm  || '20'),
      lh_url: sv.lh_url || LH_DEFAULTS.lh_url,
    }

    // Load employee data ONLY when we have a profile_id (existing employee).
    // For candidate-stage documents (offer letters in Scout) there is no profile
    // yet, so we rely entirely on the fields passed in the request body.
    let profileData: any = null
    let epData: any = null
    let compData: any[] | null = null
    if (profile_id) {
      const pr = await supabase.from('profiles')
        .select('id, full_name, email')
        .eq('id', profile_id).single()
      profileData = pr.data
      const ep = await supabase.from('employee_profiles')
        .select('*').eq('id', profile_id).single()
      epData = ep.data
      const comp = await supabase.from('employee_compensation')
        .select('amount, effective_from').eq('profile_id', profile_id)
        .order('effective_from', { ascending: false }).limit(2)
      compData = comp.data
    }

    // Load the permanent address from KYC for letters that print it (Issue 3).
    // Prefer candidate_id (Scout's pre-employee stage); fall back to profile_id.
    let employee_address = ''
    if (candidate_id) {
      const k = await supabase.from('employee_kyc').select('permanent_address').eq('candidate_id', candidate_id).maybeSingle()
      if (k.data && k.data.permanent_address) employee_address = k.data.permanent_address
    }
    if (!employee_address && profile_id) {
      const k = await supabase.from('employee_kyc').select('permanent_address').eq('profile_id', profile_id).maybeSingle()
      if (k.data && k.data.permanent_address) employee_address = k.data.permanent_address
    }

    // Resolve reports_to name
    let reports_to_name = body.reports_to_name || ''
    if (!reports_to_name && epData?.reports_to) {
      const { data: mgr } = await supabase.from('profiles')
        .select('full_name').eq('id', epData.reports_to).single()
      reports_to_name = mgr?.full_name || ''
    }

    // Resolve compensation history. Stored amounts are ANNUAL CTC (source of truth).
    // Monthly is always derived as annual / 12 at print time.
    const latestComp  = compData?.[0]?.amount || null
    const previousComp = compData?.[1]?.amount || null

    // Annual figures: prefer explicit body values, else stored annual comp.
    // NOTE: body.monthly_ctc is a legacy alias that actually carries an ANNUAL
    // amount (older Scout payloads). Stock now sends body.annual_ctc. Both are
    // accepted here and treated as annual.
    const annualBase      = num(body.monthly_ctc)   ?? num(body.annual_ctc)    ?? latestComp
    const annualProbation = num(body.probation_ctc) ?? annualBase
    const annualConfirmed = num(body.confirmed_ctc) ?? null
    const annualOld       = num(body.old_ctc)       ?? previousComp
    const annualNew       = num(body.new_ctc)       ?? latestComp

    const p: Record<string,any> = {
      ...body,
      employee_name:   profileData?.full_name || body.employee_name || '',
      role_title:      epData?.designation || epData?.role || body.role_title || '',
      department:      epData?.department ? (epData.department.replace(/_/g, ' ')) : body.department || '',
      joining_date:    epData?.joining_date || body.joining_date || '',
      // Annual CTC (source of truth)
      annual_ctc:           annualBase,
      annual_probation_ctc: annualProbation,
      annual_confirmed_ctc: annualConfirmed,
      annual_old_ctc:       annualOld,
      annual_new_ctc:       annualNew,
      // Monthly = annual / 12 (derived)
      monthly_ctc:          toMonthly(annualBase),
      probation_ctc:        toMonthly(annualProbation),
      confirmed_ctc:        toMonthly(annualConfirmed),
      old_ctc:              toMonthly(annualOld),
      new_ctc:              toMonthly(annualNew),
      reports_to_name,
      employee_address,
    }

    const generators: Record<string, Function> = {
      offer_letter:              offerLetter,
      internship_offer:          internshipOffer,
      appointment_letter:        appointmentLetter,
      internship_appointment:    internshipAppointment,
      freelance_agreement:       freelanceAgreement,
      appraisal:                 appraisalLetter,
      salary_revision:           salaryRevision,
      probation_confirmation:    probationConfirmation,
      experience_letter:         experienceLetter,
      internship_completion:     internshipCompletion,
      relieving_letter:          relievingLetter,
      warning_letter:            warningLetter,
      device_handover:           deviceHandover,
    }

    const gen = generators[document_type]
    if (!gen) return NextResponse.json({ error: `Unknown document type: ${document_type}` }, { status: 400 })
    const html = gen(p, settings)

    const b64 = Buffer.from(html, 'utf-8').toString('base64')
    const filename = `${document_type.replace(/_/g,'-')}-${(p.employee_name).replace(/\s+/g,'-').toLowerCase()}-${new Date().toISOString().split('T')[0]}.html`

    // Upload to Drive
    let driveLink: string | null = null
    // driveStatus lets the client distinguish: no folder linked (skipped),
    // an upload that was attempted but failed, and a clean success.
    let driveStatus: 'uploaded' | 'failed' | 'skipped' = 'skipped'
    if (drive_folder_id) {
      try {
        const dr = await fetch(DRIVE_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'upload_file', folderId: drive_folder_id, fileName: filename, base64: b64, mimeType: 'text/html' })
        })
        const drData = await dr.json()
        if (drData?.fileLink) { driveLink = drData.fileLink; driveStatus = 'uploaded' }
        else driveStatus = 'failed'
      } catch (e) { console.error('Drive upload failed:', e); driveStatus = 'failed' }
    }

    // ── Versioning rules by document type ────────────────────────────────────
    // One-time documents (offer / appointment letters) supersede: an employee
    // should hold ONE current copy. Regenerating flips the old one to
    // is_current=false, bumps the version, and records WHY it was replaced.
    // Repeatable documents (appraisal, salary_revision, warning, etc.) just add
    // a new row each time — they are genuine history, not replacements.
    const ONE_TIME_TYPES = ['offer_letter', 'internship_offer', 'appointment_letter', 'internship_appointment']
    let newVersion = 1
    const supersedeReason = (body.supersede_reason || '').trim()

    if (ONE_TIME_TYPES.includes(document_type)) {
      // Find an existing current doc of this type for the same person
      // (match on profile_id when present, else candidate_id).
      let q = supabase.from('employee_documents')
        .select('id, version')
        .eq('document_type', document_type)
        .eq('is_current', true)
      if (profile_id) q = q.eq('profile_id', profile_id)
      else if (candidate_id) q = q.eq('candidate_id', candidate_id)
      const { data: existingCurrent } = await q

      if (existingCurrent && existingCurrent.length) {
        // Supersede every current copy (normally just one) and compute next version.
        const maxVer = existingCurrent.reduce((m: number, r: any) => Math.max(m, r.version || 1), 0)
        newVersion = maxVer + 1
        const ids = existingCurrent.map((r: any) => r.id)
        await supabase.from('employee_documents')
          .update({ is_current: false })
          .in('id', ids)
      }
    }

    await supabase.from('employee_documents').insert({
      profile_id: profile_id || null,
      candidate_id: candidate_id || null,
      document_type,
      label: label || null,
      version: newVersion,
      status: 'generated',
      file_url: driveLink,
      is_current: true,
      metadata: supersedeReason ? { ...p, supersede_reason: supersedeReason } : p,
      generated_at: new Date().toISOString(),
    })

    // If generating an experience letter, mark any pending requests as fulfilled
    if (document_type === 'experience_letter' && profile_id) {
      await supabase.from('experience_letter_requests')
        .update({ status: 'fulfilled' })
        .eq('profile_id', profile_id)
        .eq('status', 'pending')
    }

    return NextResponse.json({ html, filename, driveLink, driveStatus }, { headers: CORS_HEADERS })
  } catch (err: any) {
    console.error('Generate error:', err)
    return NextResponse.json({ error: err.message }, { status: 500, headers: CORS_HEADERS })
  }
}
